appsmith.onReady(() => {
  renderPolicyDrift();
});
appsmith.onModelChange(() => {
  renderPolicyDrift();
});
function renderPolicyDrift() {
  const data = appsmith.model;
  const scanVars = data.scan_variables || [];
  const metrics = data.metrics || {};

  // 1. Update Verdict Banner
  const totalViolations = metrics.violations || 0;
  const violationRate = metrics.rate || 0;
  document.getElementById('violation-count').textContent = totalViolations;
  const verdictEl = document.getElementById('drift-verdict');
  if (violationRate > 0) {
    verdictEl.textContent = "NON-COMPLIANT";
    verdictEl.className = "value text-critical";
  } else {
    verdictEl.textContent = "COMPLIANT";
    verdictEl.className = "value text-safe";
    document.querySelector('.verdict-banner').style.borderLeftColor = "#2ecc71";
  }

  // 2. Populate Mismatch Table
  const tbody = document.getElementById('mismatch-table-body');
  tbody.innerHTML = "";

  // Filter only variables actually used in the model that are non-compliant
  const violations = scanVars.filter(v => v.status === "used in the model" && v.compliant === "no");
  if (violations.length === 0) {
    tbody.innerHTML = `<tr><td colspan="4" style="text-align:center; padding: 20px; color: #7f8c8d;">No policy drift detected. All observed features align with governance policy.</td></tr>`;
    return;
  }
  violations.forEach(v => {
    const tr = document.createElement('tr');

    // Define Impact based on data content (highlighting known PII)
    const piiFields = ["FirstName", "LastName", "Gender", "Age"];
    const isCritical = piiFields.includes(v.variable);
    const impactBadge = isCritical ? `<span class="badge badge-critical">Restricted Used</span>` : `<span class="badge badge-warning">Needs Review</span>`;
    tr.innerHTML = `
            <td><strong>${v.variable}</strong></td>
            <td>${v.reasoning}</td>
            <td>${impactBadge}</td>
            <td><span class="evidence-text">${v.sentence}</span></td>
        `;
    tbody.appendChild(tr);
  });
}

